            tokens.append(s[i])
            i += 1
        elif s[i].isalpha():
            tokens.append(s[i])
            i += 1
        else:
            i += 1
    pos = [0]
    def parse_expr():
        left = parse_primary()
        while pos[0] < len(tokens) and tokens[pos[0]] == '*':
            pos[0] += 1
            right = parse_primary()
            left = ('*', left, right)
        return left
    def parse_primary():
        if pos[0] >= len(tokens):
            return 'x'
        if tokens[pos[0]] == '(':
            pos[0] += 1
            expr = parse_expr()
            if pos[0] < len(tokens) and tokens[pos[0]] == ')':
                pos[0] += 1
            return expr
        else:
            var = tokens[pos[0]]
            pos[0] += 1
            return var
    return parse_expr()

def parse_equation(eq_str):
